select count(*) from postgres.comments as c, postgres.postlinks as pl, postgres.posthistory as ph, postgres.votes as v, postgres.posts as p where pl.postid = p.id and c.postid = p.id and v.postid = p.id and ph.postid = p.id and pl.linktypeid=1 and pl.creationdate>=timestamp '2011-06-14 13:31:35' and v.creationdate>=timestamp '2010-07-19 00:00:00' and v.creationdate<=timestamp '2014-09-10 00:00:00';
